43	function priceQuoteStep(step: QuoteStep): { premium: number } {
44	  const policyBase = step.items.reduce(
45	    (sum, item) => sum + itemBasePremium(item),
46	    0,
47	  );
48	  const itemSurchargeTotal = step.items.reduce(
49	    (sum, item) => sum + itemSurcharges(item),
50	    0,
51	  );
52	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
53	  const premium = Math.ceil(
54	    policyBase + itemSurchargeTotal + firstInsurance + PROCESSING_FEE,
55	  );
56	  return { premium };
57	}
